        sb.append("<Message>").append(escapeXml(result.getMessage())).append("</Message>");
        sb.append("<TransactionId>").append(escapeXml(result.getTransactionId())).append("</TransactionId>");
        if (!result.getErrors().isEmpty()) {
            sb.append("<Errors>");
            for (String error : result.getErrors()) {
                sb.append("<Error>").append(escapeXml(error)).append("</Error>");
            }
            sb.append("</Errors>");
        }
        sb.append("</ProcessingResponse>");
        return sb.toString();
