// XML Document Parser with security features
class XmlDocumentParser {

    private static final Logger LOGGER = Logger.getLogger(XmlDocumentParser.class.getName());
    private final DocumentBuilderFactory factory;

    public XmlDocumentParser() {
        this.factory = createSecureDocumentBuilderFactory();
    }

    private DocumentBuilderFactory createSecureDocumentBuilderFactory() {
        DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
        try {
            // Security: Disable external entities to prevent XXE attacks
            dbf.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            dbf.setFeature("http://xml.org/sax/features/external-general-entities", false);
            dbf.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            dbf.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
            dbf.setXIncludeAware(false);
            dbf.setExpandEntityReferences(false);
            dbf.setNamespaceAware(true);
        } catch (ParserConfigurationException e) {
            LOGGER.log(Level.WARNING, "Could not set all security features on DocumentBuilderFactory", e);
        }
        return dbf;
    }

    public Document parseXml(String xmlContent) throws Exception {
        if (xmlContent == null || xmlContent.trim().isEmpty()) {
            throw new IllegalArgumentException("XML content cannot be null or empty");
        }

        DocumentBuilder builder = factory.newDocumentBuilder();
        InputSource inputSource = new InputSource(new StringReader(xmlContent));
        Document document = builder.parse(inputSource);
        document.getDocumentElement().normalize();

        LOGGER.info("Successfully parsed XML document with root element: " +
                document.getDocumentElement().getNodeName());

        return document;
    }

    public Document parseXmlStream(InputStream inputStream) throws Exception {
        if (inputStream == null) {
            throw new IllegalArgumentException("Input stream cannot be null");
        }

        DocumentBuilder builder = factory.newDocumentBuilder();
        Document document = builder.parse(inputStream);
        document.getDocumentElement().normalize();

        return document;
    }

    public ValidationResult validateXml(String xmlContent) {
        ValidationResult result = new ValidationResult();

        if (xmlContent == null || xmlContent.trim().isEmpty()) {
            result.addError("XML content is null or empty");
            return result;
        }

        try {
            Document document = parseXml(xmlContent);
            validateStructure(document.getDocumentElement(), result, "");
        } catch (Exception e) {
            result.addError("XML parsing failed: " + e.getMessage());
        }

        return result;
    }

    private void validateStructure(Element element, ValidationResult result, String path) {
        String currentPath = path.isEmpty() ? element.getNodeName() : path + "/" + element.getNodeName();

        // Check for empty text content in leaf nodes
        NodeList children = element.getChildNodes();
        boolean hasElementChildren = false;

        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() == Node.ELEMENT_NODE) {
                hasElementChildren = true;
                validateStructure((Element) child, result, currentPath);
            }
        }

        if (!hasElementChildren) {
            String textContent = element.getTextContent().trim();
            if (textContent.isEmpty()) {
                result.addWarning("Empty element found at: " + currentPath);
            }
        }

        // Validate required attributes
        if (element.getNodeName().equals("Record") && !element.hasAttribute("id")) {
            result.addWarning("Record element at " + currentPath + " is missing 'id' attribute");
        }
        if (element.getNodeName().equals("Entity") && !element.hasAttribute("type")) {
            result.addWarning("Entity element at " + currentPath + " is missing 'type' attribute");
        }
    }

    public Map<String, Object> extractDocumentStructure(Document document) {
        Map<String, Object> structure = new LinkedHashMap<>();
        extractNodeStructure(document.getDocumentElement(), structure);
        return structure;
    }

    @SuppressWarnings("unchecked")
    private void extractNodeStructure(Element element, Map<String, Object> structure) {
        // Extract attributes
        NamedNodeMap attributes = element.getAttributes();
        if (attributes.getLength() > 0) {
            Map<String, String> attrs = new LinkedHashMap<>();
            for (int i = 0; i < attributes.getLength(); i++) {
                Node attr = attributes.item(i);
                attrs.put(attr.getNodeName(), attr.getNodeValue());
            }
            structure.put("@attributes", attrs);
        }

        // Extract child elements
        NodeList children = element.getChildNodes();
        Map<String, List<Map<String, Object>>> childElements = new LinkedHashMap<>();

        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() == Node.ELEMENT_NODE) {
                Element childElement = (Element) child;
                String childName = childElement.getNodeName();

                childElements.computeIfAbsent(childName, k -> new ArrayList<>());

                Map<String, Object> childStructure = new LinkedHashMap<>();
                extractNodeStructure(childElement, childStructure);
                childElements.get(childName).add(childStructure);
            } else if (child.getNodeType() == Node.TEXT_NODE) {
                String text = child.getTextContent().trim();
                if (!text.isEmpty()) {
                    structure.put("#text", text);
                }
            }
        }

        for (Map.Entry<String, List<Map<String, Object>>> entry : childElements.entrySet()) {
            if (entry.getValue().size() == 1) {
                structure.put(entry.getKey(), entry.getValue().get(0));
            } else {
                structure.put(entry.getKey(), entry.getValue());
            }
        }
    }
}

// Data Import Processor
class DataImportProcessor {

    private static final Logger LOGGER = Logger.getLogger(DataImportProcessor.class.getName());
    private final ConcurrentHashMap<String, List<Map<String, String>>> dataStore;
    private int transactionCounter = 0;

    public DataImportProcessor() {
        this.dataStore = new ConcurrentHashMap<>();
    }

    public ProcessingResult processDocument(Document document) {
        ProcessingResult result = new ProcessingResult();
        result.setTransactionId(generateTransactionId());

        try {
            Element root = document.getDocumentElement();
            LOGGER.info("Processing document with root element: " + root.getNodeName());

            // Process header if present
            NodeList headerNodes = root.getElementsByTagName("Header");
            if (headerNodes.getLength() > 0) {
                processHeader((Element) headerNodes.item(0), result);
            }

            // Process entities
            NodeList entityNodes = root.getElementsByTagName("Entity");
            for (int i = 0; i < entityNodes.getLength(); i++) {
                Element entityElement = (Element) entityNodes.item(i);
                // Only process direct Entity children (not deeply nested ones already handled)
                if (isDirectEntityChild(entityElement, root)) {
                    processEntity(entityElement, result);
                }
            }

            result.setStatus("SUCCESS");
            result.setMessage("Document processed successfully");

        } catch (Exception e) {
            result.setStatus("FAILED");
            result.setMessage("Processing failed: " + e.getMessage());
            result.addError(e.getMessage());
            LOGGER.log(Level.SEVERE, "Document processing failed", e);
        }

        LOGGER.info("Processing complete - Records processed: " + result.getRecordsProcessed() +
                ", Failed: " + result.getRecordsFailed());

        return result;
    }

    private boolean isDirectEntityChild(Element entity, Element root) {
        Node parent = entity.getParentNode();
        while (parent != null && parent != root) {
            if (parent.getNodeName().equals("Entities")) {
                return true;
            }
            if (parent.getNodeName().equals("Entity")) {
                return false; // Nested entity, will be handled by parent
            }
            parent = parent.getParentNode();
        }
        return true;
    }

    public ProcessingResult importData(Document document, ImportConfiguration config) {
        ProcessingResult result = new ProcessingResult();
        result.setTransactionId(generateTransactionId());

        try {
            LOGGER.info("Starting data import with type: " + config.getImportType());

            if ("FULL_SYNC".equals(config.getImportType())) {
                dataStore.clear();
                LOGGER.info("Full sync - cleared existing data");
            }

            Element root = document.getDocumentElement();
            NodeList entityNodes = root.getElementsByTagName("Entity");

            for (int i = 0; i < entityNodes.getLength(); i++) {
                Element entityElement = (Element) entityNodes.item(i);
                processEntity(entityElement, result);
            }

            result.setStatus("SUCCESS");
            result.setMessage("Data import completed successfully with type: " + config.getImportType());

        } catch (Exception e) {
            result.setStatus("PARTIAL_FAILURE");
            result.setMessage("Import encountered errors: " + e.getMessage());
            result.addError(e.getMessage());
        }

        return result;
    }

    public List<ProcessingResult> processBatch(Document document) {
        List<ProcessingResult> results = new ArrayList<>();

        Element root = document.getDocumentElement();
        NodeList batchNodes = root.getElementsByTagName("Batch");

        for (int i = 0; i < batchNodes.getLength(); i++) {
            Element batchElement = (Element) batchNodes.item(i);
            String batchId = batchElement.getAttribute("id");

            ProcessingResult batchResult = new ProcessingResult();
            batchResult.setTransactionId(generateTransactionId() + "-" + batchId);

            try {
                LOGGER.info("Processing batch: " + batchId);

                NodeList entityNodes = batchElement.getElementsByTagName("Entity");
                for (int j = 0; j < entityNodes.getLength(); j++) {
                    processEntity((Element) entityNodes.item(j), batchResult);
                }

                batchResult.setStatus("SUCCESS");
                batchResult.setMessage("Batch " + batchId + " processed successfully");

            } catch (Exception e) {
                batchResult.setStatus("FAILED");
                batchResult.setMessage("Batch " + batchId + " failed: " + e.getMessage());
                batchResult.addError(e.getMessage());
            }

            results.add(batchResult);
        }

        return results;
    }

    private void processHeader(Element headerElement, ProcessingResult result) {
        NodeList children = headerElement.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() == Node.ELEMENT_NODE) {
                LOGGER.info("Header - " + child.getNodeName() + ": " + child.getTextContent().trim());
            }
        }
    }

    private void processEntity(Element entityElement, ProcessingResult result) {
        String entityType = entityElement.getAttribute("type");
        LOGGER.info("Processing entity type: " + entityType);

        NodeList recordNodes = entityElement.getChildNodes();
        for (int i = 0; i < recordNodes.getLength(); i++) {
            Node node = recordNodes.item(i);
            if (node.getNodeType() == Node.ELEMENT_NODE && node.getNodeName().equals("Record")) {
                try {
                    processRecord((Element) node, entityType, result);
                    result.incrementProcessed();
                } catch (Exception e) {
                    result.incrementFailed();
                    result.addError("Failed to process record in entity " + entityType + ": " + e.getMessage());
                    LOGGER.log(Level.WARNING, "Failed to process record", e);
                }
            }
        }
    }

    private void processRecord(Element recordElement, String entityType, ProcessingResult result) {
        String recordId = recordElement.getAttribute("id");
        Map<String, String> recordData = new LinkedHashMap<>();
        recordData.put("_id", recordId);
        recordData.put("_entityType", entityType);

        LOGGER.info("Processing record: " + recordId + " of type: " + entityType);

        NodeList children = recordElement.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() == Node.ELEMENT_NODE) {
                Element childElement = (Element) child;

                if (childElement.getNodeName().equals("Field")) {
                    String fieldName = childElement.getAttribute("name");
                    String fieldValue = childElement.getTextContent().trim();
                    recordData.put(fieldName, fieldValue);
                    LOGGER.fine("  Field: " + fieldName + " = " + fieldValue);
                } else if (childElement.getNodeName().equals("NestedEntity")) {
                    processNestedEntity(childElement, recordId, entityType, result);
                }
            }
        }

        // Store the record
        dataStore.computeIfAbsent(entityType, k -> Collections.synchronizedList(new ArrayList<>()));
        dataStore.get(entityType).add(recordData);

        LOGGER.info("Stored record " + recordId + " with " + recordData.size() + " fields");
    }

    private void processNestedEntity(Element nestedEntityElement, String parentRecordId,
                                      String parentEntityType, ProcessingResult result) {
        String nestedType = nestedEntityElement.getAttribute("type");
        String qualifiedType = parentEntityType + "." + nestedType;

        LOGGER.info("Processing nested entity: " + nestedType + " for parent: " + parentRecordId);

        // Check if nested entity contains records or direct fields
        NodeList children = nestedEntityElement.getChildNodes();
        boolean hasRecords = false;

        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() == Node.ELEMENT_NODE) {
                Element childElement = (Element) child;

                if (childElement.getNodeName().equals("Record")) {
                    hasRecords = true;
                    try {
                        Map<String, String> nestedRecordData = new LinkedHashMap<>();
                        String nestedRecordId = childElement.getAttribute("id");
                        nestedRecordData.put("_id", nestedRecordId);
                        nestedRecordData.put("_parentId", parentRecordId);
                        nestedRecordData.put("_parentType", parentEntityType);
                        nestedRecordData.put("_entityType", qualifiedType);

                        // Extract fields from nested record
                        NodeList recordChildren = childElement.getChildNodes();
                        for (int j = 0; j < recordChildren.getLength(); j++) {
                            Node recordChild = recordChildren.item(j);
                            if (recordChild.getNodeType() == Node.ELEMENT_NODE) {
                                Element recordChildElement = (Element) recordChild;
                                if (recordChildElement.getNodeName().equals("Field")) {
                                    nestedRecordData.put(recordChildElement.getAttribute("name"),
                                            recordChildElement.getTextContent().trim());
                                } else if (recordChildElement.getNodeName().equals("NestedEntity")) {
                                    // Recursively process deeper nesting
                                    processNestedEntity(recordChildElement, nestedRecordId,
                                            qualifiedType, result);
                                }
                            }
                        }

                        dataStore.computeIfAbsent(qualifiedType,
                                k -> Collections.synchronizedList(new ArrayList<>()));
                        dataStore.get(qualifiedType).add(nestedRecordData);
                        result.incrementProcessed();

                        LOGGER.info("Stored nested record " + nestedRecordId + " of type " + qualifiedType);

                    } catch (Exception e) {
                        result.incrementFailed();
                        result.addError("Failed to process nested record in " + qualifiedType +
                                ": " + e.getMessage());
                    }
                } else if (childElement.getNodeName().equals("Field") && !hasRecords) {
                    // Direct fields in nested entity (not wrapped in Record)
                    Map<String, String> nestedData = new LinkedHashMap<>();
                    nestedData.put("_parentId", parentRecordId);
                    nestedData.put("_parentType", parentEntityType);
                    nestedData.put("_entityType", qualifiedType);

                    // Collect all fields
                    for (int j = 0; j < children.getLength(); j++) {
                        Node fieldNode = children.item(j);
                        if (fieldNode.getNodeType() == Node.ELEMENT_NODE &&
                                fieldNode.getNodeName().equals("Field")) {
                            Element fieldElement = (Element) fieldNode;
                            nestedData.put(fieldElement.getAttribute("name"),
                                    fieldElement.getTextContent().trim());
                        }
                    }

                    dataStore.computeIfAbsent(qualifiedType,
                            k -> Collections.synchronizedList(new ArrayList<>()));
                    dataStore.get(qualifiedType).add(nestedData);
                    result.incrementProcessed();

                    LOGGER.info("Stored nested entity data of type " + qualifiedType +
                            " for parent " + parentRecordId);
                    break; // Already processed all fields
                }
            }
        }
    }

    private synchronized String generateTransactionId() {
        transactionCounter++;
        return "TXN-" + System.currentTimeMillis() + "-" + transactionCounter;
    }

    public Map<String, List<Map<String, String>>> getDataStore() {
        return Collections.unmodifiableMap(dataStore);
    }
}

// Processing Result
class ProcessingResult {
    private String status;
    private String message;
    private String transactionId;
    private int recordsProcessed;
    private int recordsFailed;
    private final List<String> errors;

    public ProcessingResult() {
        this.errors = new ArrayList<>();
        this.recordsProcessed = 0;
        this.recordsFailed = 0;
    }

    public String getStatus() { return status; }
    public void setStatus(String status) { this.status = status; }

    public String getMessage() { return message; }
    public void setMessage(String message) { this.message = message; }

    public String getTransactionId() { return transactionId; }
    public void setTransactionId(String transactionId) { this.transactionId = transactionId; }

    public int getRecordsProcessed() { return recordsProcessed; }
    public void incrementProcessed() { this.recordsProcessed++; }

    public int getRecordsFailed() { return recordsFailed; }
    public void incrementFailed() { this.recordsFailed++; }

    public List<String> getErrors() { return Collections.unmodifiableList(errors); }
    public void addError(String error) { this.errors.add(error); }
}

// Validation Result
class ValidationResult {
    private final List<String> errors;
    private final List<String> warnings;

    public ValidationResult() {
        this.errors = new ArrayList<>();
        this.warnings = new ArrayList<>();
    }

    public boolean isValid() { return errors.isEmpty(); }

    public List<String> getErrors() { return Collections.unmodifiableList(errors); }
    public void addError(String error) { this.errors.add(error); }

    public List<String> getWarnings() { return Collections.unmodifiableList(warnings); }
    public void addWarning(String warning) { this.warnings.add(warning); }
}

// Import Configuration
class ImportConfiguration {
    private final String importType;
    private boolean validateBeforeImport;
    private boolean continueOnError;
    private int batchSize;

    public ImportConfiguration(String importType) {
        this.importType = importType;
        this.validateBeforeImport = true;
        this.continueOnError = true;
        this.batchSize = 1000;
    }

    public String getImportType() { return importType; }
    public boolean isValidateBeforeImport() { return validateBeforeImport; }
    public void setValidateBeforeImport(boolean validate) { this.validateBeforeImport = validate; }
    public boolean isContinueOnError() { return continueOnError; }
    public void setContinueOnError(boolean continueOnError) { this.continueOnError = continueOnError; }
    public int getBatchSize() { return batchSize; }
    public void setBatchSize(int batchSize) { this.batchSize = batchSize; }
}

// SOAP Message Handler for raw SOAP processing
class SoapMessageHandler {

    private static final Logger LOGGER = Logger.getLogger(SoapMessageHandler.class.getName());
    private final XmlDocumentParser xmlParser;
    private final DataImportProcessor importProcessor;

    public SoapMessageHandler() {
        this.xmlParser = new XmlDocumentParser();
        this.importProcessor = new DataImportProcessor();
    }

    public SOAPMessage handleSoapRequest(SOAPMessage soapRequest) throws SOAPException {
        try {
            SOAPBody requestBody = soapRequest.getSOAPBody();
            Iterator<?> iterator = requestBody.getChildElements();

            String operation = null;
            String payload = null;

            while (iterator.hasNext()) {
                Node node = (Node) iterator.next();
                if (node.getNodeType() == Node.ELEMENT_NODE) {
                    operation = node.getLocalName();
                    payload = node.getTextContent();
                    break;
                }
            }

            LOGGER.info("Handling SOAP request for operation: " + operation);

            String responseContent;
            if ("processDocument".equals(operation)) {
                Document doc = xmlParser.parseXml(payload);
                ProcessingResult result = importProcessor.processDocument(doc);
                responseContent = formatResult(result);
            } else {
                responseContent = "Unknown operation: " + operation;
            }

            return createSoapResponse(responseContent);

        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Error handling SOAP request", e);
            return createSoapFaultResponse(e.getMessage());
        }
    }

    private SOAPMessage createSoapResponse(String content) throws SOAPException {
        MessageFactory messageFactory = MessageFactory.newInstance();
        SOAPMessage soapResponse = messageFactory.createMessage();
        SOAPBody responseBody = soapResponse.getSOAPBody();

        SOAPElement responseElement = responseBody.addChildElement("ProcessingResponse");
        responseElement.addTextNode(content);

        soapResponse.saveChanges();
        return soapResponse;
    }

    private SOAPMessage createSoapFaultResponse(String faultMessage) throws SOAPException {
        MessageFactory messageFactory = MessageFactory.newInstance();
        SOAPMessage soapResponse = messageFactory.createMessage();
        SOAPBody responseBody = soapResponse.getSOAPBody();

        SOAPFault fault = responseBody.addFault();
        fault.setFaultString(faultMessage);
        fault.setFaultCode("Server");

        soapResponse.saveChanges();
        return soapResponse;
    }

    private String formatResult(ProcessingResult result) {
        return String.format("Status: %s, Processed: %d, Failed: %d, Transaction: %s",
                result.getStatus(), result.getRecordsProcessed(),
                result.getRecordsFailed(), result.getTransactionId());
    }
}

// Large Payload Streaming Processor
class LargePayloadProcessor {

    private static final Logger LOGGER = Logger.getLogger(LargePayloadProcessor.class.getName());
    private static final int CHUNK_SIZE = 100;

    private final XmlDocumentParser xmlParser;
    private final DataImportProcessor importProcessor;

    public LargePayloadProcessor() {
        this.xmlParser = new XmlDocumentParser();
        this.importProcessor = new DataImportProcessor();
    }

    public ProcessingResult processLargePayload(InputStream inputStream) {
        ProcessingResult overallResult = new ProcessingResult();
        overallResult.setTransactionId("LARGE-" + System.currentTimeMillis());

        try {
            Document document = xmlParser.parseXmlStream(inputStream);
            Element root = document.getDocumentElement();

            NodeList entityNodes = root.getElementsByTagName("Entity");
            int totalEntities = entityNodes.getLength();

            LOGGER.info("Processing large payload with " + totalEntities + " entities");

            int processed = 0;
            while (processed < totalEntities) {
                int end = Math.min(processed + CHUNK_SIZE, totalEntities);
                LOGGER.info("Processing chunk: " + processed + " to " + end);

                for (int i = processed; i < end; i++) {
                    Element entityElement = (Element) entityNodes.item(i);
                    try {
                        processEntityChunk(entityElement, overallResult);
                    } catch (Exception e) {
                        overallResult.addError("Error in entity at index " + i + ": " + e.getMessage());
                    }
                }

                processed = end;
                LOGGER.info("Progress: " + processed + "/" + totalEntities + " entities processed");
            }

            overallResult.setStatus("SUCCESS");
            overallResult.setMessage("Large payload processed: " + totalEntities + " entities");

        } catch (Exception e) {
            overallResult.setStatus("FAILED");
            overallResult.setMessage("Large payload processing failed: " + e.getMessage());
            overallResult.addError(e.getMessage());
            LOGGER.log(Level.SEVERE, "Large payload processing failed", e);
        }

        return overallResult;
    }

    private void processEntityChunk(Element entityElement, ProcessingResult result) {
        String entityType = entityElement.getAttribute("type");
        NodeList records = entityElement.getElementsByTagName("Record");

        for (int i = 0; i < records.getLength(); i++) {
            try {
                result.incrementProcessed();
            } catch (Exception e) {
                result.incrementFailed();
                result.addError("Failed record in " + entityType + ": " + e.getMessage());
            }
        }
    }
}